/**
 * Builds the 3 PFN tool JS bundles the way the parent skm repo does
 * (webpack.build.js -> MergeIntoSingleFilePlugin + minify transform): each
 * bundle is a single source fragment written to one file. No babel, no webpack
 * module wrapper — top-level declarations stay global, which the tools rely on
 * (inline onclick="fn()" handlers).
 *
 * Modes:
 *   node scripts/build-bundles.js            production: minified + CONTENT-HASHED
 *                                            filenames, and regenerates
 *                                            js-side-menu-config.php with them.
 *   node scripts/build-bundles.js --dev      dev: unminified, stable (non-hashed)
 *                                            filenames — served locally via
 *                                            dev-config.php.
 *   node scripts/build-bundles.js --watch    dev + rebuild on source change.
 *
 * Production hashing mirrors skm: a new source => a new hash => a new S3 object,
 * and js-side-menu-config.php is committed by the bundle.yml GitHub Action so
 * the app points at the freshly-uploaded bundle. terser is used (uglify-js
 * rejects a sloppy-mode `delete <localVar>` present in the sources).
 *
 * Output: js/production/pfn-proxy/<name>-bundle[-<hash>].js
 */
const fs = require("fs");
const path = require("path");
const crypto = require("crypto");
const { minify } = require("terser");

const ROOT = path.resolve(__dirname, "..");
const OUT_DIR = path.join(ROOT, "js/production/pfn-proxy");
const SRC_DIR = path.join(ROOT, "js/fragments");
const CONFIG_FILE = path.join(ROOT, "js-side-menu-config.php");

const BUNDLES = [
  { out: "mockdraft-simulator-bundle", src: "mockdraft-simulator.js", constant: "MOCKDRAFT_SIMULATOR_SCRIPT_LOCATION" },
  { out: "ultimate-simulator-bundle", src: "ultimate-simulator.js", constant: "ULTIMATE_SIMULATOR_SCRIPT_LOCATION" },
  { out: "playoff-predictor-bundle", src: "playoff-predictor.js", constant: "PLAYOFF_PREDICTOR_SCRIPT_LOCATION" },
];

const WATCH = process.argv.includes("--watch");
const DEV = WATCH || process.argv.includes("--dev");

function removeExisting(prefix) {
  for (const f of fs.readdirSync(OUT_DIR)) {
    if (f === `${prefix}.js` || (f.startsWith(`${prefix}-`) && f.endsWith(".js"))) {
      fs.unlinkSync(path.join(OUT_DIR, f));
    }
  }
}

// Returns the output filename (with hash in prod), or null on failure.
async function buildOne(b) {
  const code = fs.readFileSync(path.join(SRC_DIR, b.src), "utf8");
  let out = code;
  if (!DEV) {
    const result = await minify(code);
    if (result.error) {
      console.error(`ERROR minifying ${b.src}:`, result.error);
      return null;
    }
    out = result.code;
  }
  removeExisting(b.out); // avoid stale hashed copies piling up
  const hash = DEV ? "" : "-" + crypto.createHash("md5").update(out).digest("hex").slice(0, 10);
  const fname = `${b.out}${hash}.js`;
  fs.writeFileSync(path.join(OUT_DIR, fname), out);
  console.log(`built ${fname}  (${(out.length / 1024).toFixed(1)} KiB${DEV ? ", dev/unminified" : ""})`);
  return fname;
}

function writeConfig(nameByConstant) {
  const lines = BUNDLES.map(
    (b) => `define('${b.constant}', BUNDLE_STATIC_URL . '/js/production/pfn-proxy/${nameByConstant[b.constant]}');`
  );
  const header =
    "<?php\n" +
    "// Auto-generated by scripts/build-bundles.js (npm run build). Do not edit by hand.\n" +
    "// Production JS bundle locations (content-hashed), served from the CDN / S3.\n" +
    "// The bundle.yml GitHub Action rebuilds these, uploads the hashed files to S3,\n" +
    "// and commits this file back to the PR.\n";
  fs.writeFileSync(CONFIG_FILE, header + lines.join("\n") + "\n");
  console.log("updated js-side-menu-config.php");
}

async function buildAll() {
  fs.mkdirSync(OUT_DIR, { recursive: true });
  const nameByConstant = {};
  let ok = true;
  for (const b of BUNDLES) {
    const fname = await buildOne(b);
    if (!fname) ok = false;
    else nameByConstant[b.constant] = fname;
  }
  // Only the production (hashed) build owns js-side-menu-config.php.
  if (ok && !DEV) writeConfig(nameByConstant);
  return ok;
}

(async () => {
  const ok = await buildAll();

  if (!WATCH) {
    process.exit(ok ? 0 : 1);
    return;
  }

  const srcToBundle = {};
  for (const b of BUNDLES) srcToBundle[b.src] = b;

  console.log("\nwatching js/fragments/ for changes (Ctrl+C to stop)...");
  let timer = null;
  const pending = new Set();
  const flush = async () => {
    timer = null;
    const files = [...pending];
    pending.clear();
    for (const f of files) await buildOne(srcToBundle[f]);
  };
  fs.watch(SRC_DIR, (_event, filename) => {
    if (!filename || !srcToBundle[filename]) return;
    pending.add(filename);
    if (timer) clearTimeout(timer);
    timer = setTimeout(flush, 150); // debounce noisy fs events
  });
})();
